function calcEngagementRate(engagedSessions, totalSessions) {
  return (engagedSessions / totalSessions) * 100;
}

function calcDay1Retention(day1Users, installDayUsers) {
  return (day1Users / installDayUsers) * 100;
}

function calcStickiness(dau, mau) {
  return (dau / mau) * 100;
}

const data = {
  totalSessions: 120000,
  engagedSessions: 84000,
  installDayUsers: 5000,
  day1Users: 1750,
  dau: 45000,
  mau: 200000
};

console.log('エンゲージメント率:', calcEngagementRate(data.engagedSessions, data.totalSessions).toFixed(1) + '%');
console.log('Day1 Retention:', calcDay1Retention(data.day1Users, data.installDayUsers).toFixed(1) + '%');
console.log('Stickiness:', calcStickiness(data.dau, data.mau).toFixed(1) + '%');
